-/// Compute deterministic chunk boundaries aligned to newline positions.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum BoundaryKind {
+    Newline,
+    StatementTerminator,
+    BlockBoundary,
+}
